example.code:
{
  "project_id": "ACME",
  "issue_types": [
    {
      "name": "Story",
      "workflow_id": "wf-scrum-v3"
    },
    {
      "name": "Bug",
      "workflow_id": "wf-bug-v2"
    }
  ],
  "workflow": {
    "statuses": [
      {
        "name": "Backlog",
        "category": "to-do"
      },
      {
        "name": "In Progress",
        "category": "in-progress"
      },
      {
        "name": "In Review",
        "category": "in-progress"
      },
      {
        "name": "Done",
        "category": "done"
      }
    ],
    "transitions": [
      {
        "from": "Backlog",
        "to": "In Progress",
        "name": "Start"
      },
      {
        "from": "In Progress",
        "to": "In Review",
        "name": "Submit for review"
      },
      {
        "from": "In Review",
        "to": "Done",
        "name": "Approve"
      }
    ]
  },
  "automation_rules": [
    {
      "namespace": "ACME/board/auto-assign",
      "version": "v3",
      "trigger": "issue-created",
      "action": "assign to component lead"
    }
  ],
  "shared_filters": [
    {
      "id": "10001",
      "jql": "project = ACME AND status != Done",
      "owner": "team-acme"
    }
  ]
}
